57	class _UsersScreenState extends State<UsersScreen> {
58	  static const String _baseUrl = 'http://10.0.2.2:8000';
59	
60	  final List<UserCard> _users = [];
61	  final ScrollController _scrollController = ScrollController();
62	  final Set<int> _likedIds = {};
63	  final Set<int> _blockedIds = {};
64	
65	  int _page = 1;
66	  static const int _perPage = 30;
67	  bool _isLoading = false;
68	  bool _hasMore = true;
69	  String? _token;
70	  String? _errorMessage;
71	
72	  @override
73	  void initState() {
74	    super.initState();
75	    _init();
76	    _scrollController.addListener(_onScroll);
77	  }
78	
79	  @override
80	  void dispose() {
81	    _scrollController.dispose();
82	    super.dispose();
83	  }
84	
85	  Future<void> _init() async {
86	    _token = await ApiService.getToken();
87	    await _loadUsers();
88	  }
89	
90	  void _onScroll() {
91	    if (_scrollController.position.pixels >=
92	        _scrollController.position.maxScrollExtent - 200) {
93	      if (!_isLoading && _hasMore) {
94	        _loadUsers();
95	      }
96	    }
97	  }
98	
99	  Future<void> _loadUsers() async {
100	    if (_isLoading || !_hasMore) return;
101	    setState(() {
102	      _isLoading = true;
103	      _errorMessage = null;
104	    });
105	
106	    try {
107	      final headers = <String, String>{
108	        'Content-Type': 'application/json',
109	      };
110	      if (_token != null) {
111	        headers['Authorization'] = 'Bearer $_token';
112	      }
113	
114	      final uri = Uri.parse(
115	          '$_baseUrl/api/users?page=$_page&per_page=$_perPage');
116	      final response = await http.get(uri, headers: headers);
117	
118	      if (response.statusCode == 200) {
119	        final data = jsonDecode(response.body) as Map<String, dynamic>;
120	        final List<dynamic> rawUsers = data['users'] as List<dynamic>;
121	        final newUsers =
122	            rawUsers.map((u) => UserCard.fromJson(u as Map<String, dynamic>)).toList();
123	        setState(() {
124	          _users.addAll(newUsers);
125	          _hasMore = data['has_more'] as bool;
126	          _page++;
127	          _isLoading = false;
128	        });
129	      } else {
130	        setState(() {
131	          _errorMessage = 'Error ${response.statusCode}: ${response.body}';
132	          _isLoading = false;
133	        });
134	      }
135	    } catch (e) {
136	      setState(() {
137	        _errorMessage = 'Network error: $e';
138	        _isLoading = false;
139	      });
140	    }
141	  }
