143	  // ── Fetch current who-i-like list ─────────────────────────────────────────
144	
145	  Future<List<_RankItem>> _fetchWhoILike() async {
146	    try {
147	      final resp = await http.get(
148	        Uri.parse('$_baseUrl/api/who_i_like'),
149	        headers: {
150	          'Content-Type': 'application/json',
151	          if (_token != null) 'Authorization': 'Bearer $_token',
152	        },
153	      );
154	      if (resp.statusCode == 200) {
155	        final data = jsonDecode(resp.body) as Map<String, dynamic>;
156	        final users = (data['users'] as List<dynamic>).cast<Map<String, dynamic>>();
157	        return users.map((u) => _RankItem(
158	          id: u['id'] as int,
159	          username: u['username'] as String,
160	          age: u['age'] as int?,
161	          sex: u['sex'] as String?,
162	        )).toList();
163	      }
164	    } catch (_) {}
165	    return [];
166	  }
