168	  // ── Save re-ranking ───────────────────────────────────────────────────────
169	
170	  Future<void> _saveRerank(List<_RankItem> ranked) async {
171	    try {
172	      final rankings = ranked.asMap().entries.map((e) {
173	        return {'username': e.value.username, 'rank': e.key + 1};
174	      }).toList();
175	      await http.put(
176	        Uri.parse('$_baseUrl/api/like/rerank'),
177	        headers: {
178	          'Content-Type': 'application/json',
179	          if (_token != null) 'Authorization': 'Bearer $_token',
180	        },
181	        body: jsonEncode({'rankings': rankings}),
182	      );
183	    } catch (_) {}
184	  }
