186	  // ── Show ranking bottom sheet ─────────────────────────────────────────────
187	
188	  Future<void> _showRankingSheet(UserCard newUser, List<_RankItem> currentLikes) async {
189	    // Build initial list: existing likes + newly liked person at bottom
190	    final items = [
191	      ...currentLikes,
192	      _RankItem(
193	        id: newUser.id,
194	        username: newUser.username,
195	        age: newUser.age,
196	        sex: newUser.sex,
197	      ),
198	    ];
199	
200	    final saved = await showModalBottomSheet<bool>(
201	      context: context,
202	      isScrollControlled: true,
203	      backgroundColor: const Color(0xFF0E0E0E),
204	      shape: const RoundedRectangleBorder(
205	        borderRadius: BorderRadius.vertical(top: Radius.circular(20)),
206	      ),
207	      builder: (ctx) => _RankingSheet(
208	        items: items,
209	        newUserId: newUser.id,
210	        baseUrl: _baseUrl,
211	        token: _token,
212	        onSave: (reordered) async {
213	          await _saveRerank(reordered);
214	          Navigator.of(ctx).pop(true);
215	        },
216	      ),
217	    );
218	
219	    if (saved == true) {
220	      // Remove the liked card from the grid
221	      setState(() {
222	        _likedIds.add(newUser.id);
223	        _users.removeWhere((u) => u.id == newUser.id);
224	      });
225	    }
226	  }
