228	  // ── Like / unlike ─────────────────────────────────────────────────────────
229	
230	  Future<void> _uploadVoiceNote(int likedUserId, String filePath) async {
231	    try {
232	      final request = http.MultipartRequest(
233	        'POST',
234	        Uri.parse('$_baseUrl/api/like/$likedUserId/voice'),
235	      );
236	      if (_token != null) {
237	        request.headers['Authorization'] = 'Bearer $_token';
238	      }
239	      request.files.add(await http.MultipartFile.fromPath(
240	        'file',
241	        filePath,
242	        filename: 'voice_note.m4a',
243	      ));
244	      await request.send();
245	    } catch (_) {}
246	  }
247	
248	  Future<void> _likeUser(UserCard user) async {
249	    if (_likedIds.contains(user.id)) {
250	      // Unlike
251	      try {
252	        await http.delete(
253	          Uri.parse('$_baseUrl/api/like/${user.id}'),
254	          headers: {
255	            'Content-Type': 'application/json',
256	            if (_token != null) 'Authorization': 'Bearer $_token',
257	          },
258	        );
259	        setState(() => _likedIds.remove(user.id));
260	      } catch (_) {}
261	      return;
262	    }
263	
264	    // Step 1: Show voice recorder before any API calls
265	    if (!mounted) return;
266	    final audioPath = await showModalBottomSheet<String>(
267	      context: context,
268	      isScrollControlled: true,
269	      backgroundColor: Colors.transparent,
270	      builder: (ctx) => VoiceNoteRecorder(username: user.username),
271	    );
272	
273	    // User dismissed without completing a recording
274	    if (audioPath == null) return;
275	
276	    // Step 2: POST like
277	    try {
278	      final resp = await http.post(
279	        Uri.parse('$_baseUrl/api/like'),
280	        headers: {
281	          'Content-Type': 'application/json',
282	          if (_token != null) 'Authorization': 'Bearer $_token',
283	        },
284	        body: jsonEncode({'liked_user_id': user.id}),
285	      );
286	      if (resp.statusCode == 201 || resp.statusCode == 200) {
287	        // Step 3: Upload voice note
288	        await _uploadVoiceNote(user.id, audioPath);
289	
290	        // Step 4: Fetch current like list and show ranking sheet
291	        final currentLikes = await _fetchWhoILike();
292	        final withoutNew = currentLikes.where((u) => u.id != user.id).toList();
293	
294	        if (!mounted) return;
295	        await _showRankingSheet(user, withoutNew);
296	      }
297	    } catch (e) {
298	      if (mounted) {
299	        ScaffoldMessenger.of(context).showSnackBar(
300	          SnackBar(content: Text('Like failed: $e')),
301	        );
302	      }
303	    }
304	  }
