306	  Future<void> _blockUser(int userId) async {
307	    try {
308	      final resp = await http.post(
309	        Uri.parse('$_baseUrl/api/block'),
310	        headers: {
311	          'Content-Type': 'application/json',
312	          if (_token != null) 'Authorization': 'Bearer $_token',
313	        },
314	        body: jsonEncode({'blocked_user_id': userId}),
315	      );
316	      if (resp.statusCode == 201 || resp.statusCode == 200) {
317	        setState(() {
318	          _blockedIds.add(userId);
319	          _users.removeWhere((u) => u.id == userId);
320	        });
321	      }
322	    } catch (_) {}
323	  }
