497	  Widget _buildBody() {
498	    if (_users.isEmpty && _isLoading) {
499	      return const Center(
500	          child: CircularProgressIndicator(color: Colors.blueAccent));
501	    }
502	
503	    if (_users.isEmpty && _errorMessage != null) {
504	      return Center(
505	        child: Padding(
506	          padding: const EdgeInsets.all(24),
507	          child: Column(
508	            mainAxisSize: MainAxisSize.min,
509	            children: [
510	              const Icon(Icons.error_outline, size: 48, color: Colors.redAccent),
511	              const SizedBox(height: 12),
512	              Text(_errorMessage!,
513	                  textAlign: TextAlign.center,
514	                  style: const TextStyle(color: Colors.redAccent)),
515	              const SizedBox(height: 16),
516	              ElevatedButton(
517	                  onPressed: _refresh, child: const Text('Retry')),
518	            ],
519	          ),
520	        ),
521	      );
522	    }
523	
524	    if (_users.isEmpty) {
525	      return const Center(
526	        child: Text('No users found.',
527	            style: TextStyle(color: Colors.grey, fontSize: 16)),
528	      );
529	    }
530	
531	    return GridView.builder(
532	      controller: _scrollController,
533	      padding: const EdgeInsets.all(8),
534	      itemCount: _users.length + (_hasMore ? 1 : 0),
535	      gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(
536	        crossAxisCount: 3,
537	        childAspectRatio: 3 / 4,
538	        crossAxisSpacing: 8,
539	        mainAxisSpacing: 8,
540	      ),
541	      itemBuilder: (context, index) {
542	        if (index >= _users.length) {
543	          // Loader tile
544	          return const Center(
545	              child: CircularProgressIndicator(color: Colors.blueAccent));
546	        }
547	        final user = _users[index];
548	        return GestureDetector(
549	          onTap: () {
550	            final photoUrl = (user.photoUrl
551	                    ?.replaceFirst('http://0.0.0.0:8000', _baseUrl)) ??
552	                '';
553	            Navigator.of(context).push(
554	              MaterialPageRoute(
555	                builder: (_) => ProfileScreen(
556	                  userId: user.id,
557	                  username: user.username,
558	                  age: user.age ?? 0,
559	                  sex: user.sex ?? 'Unknown',
560	                  photoUrl: photoUrl,
561	                ),
562	              ),
563	            );
564	          },
565	          child: _buildCard(user),
566	        );
567	      },
568	    );
569	  }
570	}
