593	class _RankingSheetState extends State<_RankingSheet> {
594	  late List<_RankItem> _items;
595	  bool _saving = false;
596	  final ScrollController _scrollController = ScrollController();
597	
598	  static const _bg = Color(0xFF12121C);
599	  static const _surface = Color(0xFF1E1E2E);
600	
601	  @override
602	  void initState() {
603	    super.initState();
604	    _items = List.from(widget.items);
605	    // Auto-scroll to the new person after the sheet renders
606	    WidgetsBinding.instance.addPostFrameCallback((_) {
607	      final newIndex = _items.indexWhere((i) => i.id == widget.newUserId);
608	      if (newIndex > 0 && _scrollController.hasClients) {
609	        final itemH = 72.0; // approximate row height
610	        _scrollController.animateTo(
611	          newIndex * itemH,
612	          duration: const Duration(milliseconds: 400),
613	          curve: Curves.easeOut,
614	        );
615	      }
616	    });
617	  }
