715	                              fontWeight: FontWeight.bold,
716	                              fontSize: 14,
717	                            ),
718	                            textAlign: TextAlign.center,
719	                          ),
720	                        ),
721	                        const SizedBox(width: 8),
722	                        // Circular photo
723	                        CircleAvatar(
724	                          radius: 22,
725	                          backgroundColor:
726	                              Colors.blueAccent.withOpacity(0.2),
727	                          child: ClipOval(
