import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import '../services/api_service.dart';
import 'profile_screen.dart';
import 'settings_screen.dart';
import 'voice_note_recorder.dart';

class UserCard {
  final int id;
  final String username;
  final int? age;
  final String? sex;
  final String? photoUrl;

  UserCard({
    required this.id,
    required this.username,
    this.age,
    this.sex,
    this.photoUrl,
  });

  factory UserCard.fromJson(Map<String, dynamic> json) {
    return UserCard(
      id: json['id'] as int,
      username: json['username'] as String,
      age: json['age'] as int?,
      sex: json['sex'] as String?,
      photoUrl: json['photo_url'] as String?,
    );
  }
}

/// Lightweight model used inside the ranking modal.
class _RankItem {
  final int id;
  final String username;
  final int? age;
  final String? sex;

  _RankItem({
    required this.id,
    required this.username,
    this.age,
    this.sex,
  });
}

class UsersScreen extends StatefulWidget {
  const UsersScreen({super.key});

  @override
  State<UsersScreen> createState() => _UsersScreenState();
}

class _UsersScreenState extends State<UsersScreen> {
  static const String _baseUrl = 'http://10.0.2.2:8000';

  final List<UserCard> _users = [];
  final ScrollController _scrollController = ScrollController();
  final Set<int> _likedIds = {};
  final Set<int> _blockedIds = {};

  int _page = 1;
  static const int _perPage = 30;
  bool _isLoading = false;
  bool _hasMore = true;
  String? _token;
  String? _errorMessage;

  @override
  void initState() {
    super.initState();
    _init();
    _scrollController.addListener(_onScroll);
  }

  @override
  void dispose() {
    _scrollController.dispose();
    super.dispose();
  }

  Future<void> _init() async {
    _token = await ApiService.getToken();
    await _loadUsers();
  }

  void _onScroll() {
    if (_scrollController.position.pixels >=
        _scrollController.position.maxScrollExtent - 200) {
      if (!_isLoading && _hasMore) {
        _loadUsers();
      }
    }
  }

  Future<void> _loadUsers() async {
    if (_isLoading || !_hasMore) return;
    setState(() {
      _isLoading = true;
      _errorMessage = null;
    });

    try {
      final headers = <String, String>{
        'Content-Type': 'application/json',
      };
      if (_token != null) {
        headers['Authorization'] = 'Bearer $_token';
      }

      final uri = Uri.parse(
          '$_baseUrl/api/users?page=$_page&per_page=$_perPage');
      final response = await http.get(uri, headers: headers);

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body) as Map<String, dynamic>;
        final List<dynamic> rawUsers = data['users'] as List<dynamic>;
        final newUsers =
            rawUsers.map((u) => UserCard.fromJson(u as Map<String, dynamic>)).toList();
        setState(() {
          _users.addAll(newUsers);
          _hasMore = data['has_more'] as bool;
          _page++;
          _isLoading = false;
        });
      } else {
        setState(() {
          _errorMessage = 'Error ${response.statusCode}: ${response.body}';
          _isLoading = false;
        });
      }
    } catch (e) {
      setState(() {
        _errorMessage = 'Network error: $e';
        _isLoading = false;
      });
    }
  }

  // ── Fetch current who-i-like list ─────────────────────────────────────────

  Future<List<_RankItem>> _fetchWhoILike() async {
    try {
      final resp = await http.get(
        Uri.parse('$_baseUrl/api/who_i_like'),
        headers: {
          'Content-Type': 'application/json',
          if (_token != null) 'Authorization': 'Bearer $_token',
        },
      );
      if (resp.statusCode == 200) {
        final data = jsonDecode(resp.body) as Map<String, dynamic>;
        final users = (data['users'] as List<dynamic>).cast<Map<String, dynamic>>();
        return users.map((u) => _RankItem(
          id: u['id'] as int,
          username: u['username'] as String,
          age: u['age'] as int?,
          sex: u['sex'] as String?,
        )).toList();
      }
    } catch (_) {}
    return [];
  }

  // ── Save re-ranking ───────────────────────────────────────────────────────

  Future<void> _saveRerank(List<_RankItem> ranked) async {
    try {
      final rankings = ranked.asMap().entries.map((e) {
        return {'username': e.value.username, 'rank': e.key + 1};
      }).toList();
      await http.put(
        Uri.parse('$_baseUrl/api/like/rerank'),
        headers: {
          'Content-Type': 'application/json',
          if (_token != null) 'Authorization': 'Bearer $_token',
        },
        body: jsonEncode({'rankings': rankings}),
      );
    } catch (_) {}
  }

  // ── Show ranking bottom sheet ─────────────────────────────────────────────

  Future<void> _showRankingSheet(UserCard newUser, List<_RankItem> currentLikes) async {
    // Build initial list: existing likes + newly liked person at bottom
    final items = [
      ...currentLikes,
      _RankItem(
        id: newUser.id,
        username: newUser.username,
        age: newUser.age,
        sex: newUser.sex,
      ),
    ];

    final saved = await showModalBottomSheet<bool>(
      context: context,
      isScrollControlled: true,
      backgroundColor: const Color(0xFF0E0E0E),
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(20)),
      ),
      builder: (ctx) => _RankingSheet(
        items: items,
        newUserId: newUser.id,
        baseUrl: _baseUrl,
        token: _token,
        onSave: (reordered) async {
          await _saveRerank(reordered);
          Navigator.of(ctx).pop(true);
        },
      ),
    );

    if (saved == true) {
      // Remove the liked card from the grid
      setState(() {
        _likedIds.add(newUser.id);
        _users.removeWhere((u) => u.id == newUser.id);
      });
    }
  }

  // ── Like / unlike ─────────────────────────────────────────────────────────

  Future<void> _uploadVoiceNote(int likedUserId, String filePath) async {
    try {
      final request = http.MultipartRequest(
        'POST',
        Uri.parse('$_baseUrl/api/like/$likedUserId/voice'),
      );
      if (_token != null) {
        request.headers['Authorization'] = 'Bearer $_token';
      }
      request.files.add(await http.MultipartFile.fromPath(
        'file',
        filePath,
        filename: 'voice_note.m4a',
      ));
      await request.send();
    } catch (_) {}
  }

  Future<void> _likeUser(UserCard user) async {
    if (_likedIds.contains(user.id)) {
      // Unlike
      try {
        await http.delete(
          Uri.parse('$_baseUrl/api/like/${user.id}'),
          headers: {
            'Content-Type': 'application/json',
            if (_token != null) 'Authorization': 'Bearer $_token',
          },
        );
        setState(() => _likedIds.remove(user.id));
      } catch (_) {}
      return;
    }

    // Step 1: Show voice recorder before any API calls
    if (!mounted) return;
    final audioPath = await showModalBottomSheet<String>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.transparent,
      builder: (ctx) => VoiceNoteRecorder(username: user.username),
    );

    // User dismissed without completing a recording
    if (audioPath == null) return;

    // Step 2: POST like
    try {
      final resp = await http.post(
        Uri.parse('$_baseUrl/api/like'),
        headers: {
          'Content-Type': 'application/json',
          if (_token != null) 'Authorization': 'Bearer $_token',
        },
        body: jsonEncode({'liked_user_id': user.id}),
      );
      if (resp.statusCode == 201 || resp.statusCode == 200) {
        // Step 3: Upload voice note
        await _uploadVoiceNote(user.id, audioPath);

        // Step 4: Fetch current like list and show ranking sheet
        final currentLikes = await _fetchWhoILike();
        final withoutNew = currentLikes.where((u) => u.id != user.id).toList();

        if (!mounted) return;
        await _showRankingSheet(user, withoutNew);
      }
    } catch (e) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(content: Text('Like failed: $e')),
        );
      }
    }
  }

  Future<void> _blockUser(int userId) async {
    try {
      final resp = await http.post(
        Uri.parse('$_baseUrl/api/block'),
        headers: {
          'Content-Type': 'application/json',
          if (_token != null) 'Authorization': 'Bearer $_token',
        },
        body: jsonEncode({'blocked_user_id': userId}),
      );
      if (resp.statusCode == 201 || resp.statusCode == 200) {
        setState(() {
          _blockedIds.add(userId);
          _users.removeWhere((u) => u.id == userId);
        });
      }
    } catch (_) {}
  }

  Future<void> _refresh() async {
    setState(() {
      _users.clear();
      _page = 1;
      _hasMore = true;
      _errorMessage = null;
    });
    await _loadUsers();
  }

  Widget _buildCard(UserCard user) {
    // Swap to Android emulator-accessible URL
    final photoUrl = user.photoUrl?.replaceFirst('http://0.0.0.0:8000', _baseUrl);

    return ClipRRect(
      borderRadius: BorderRadius.circular(12),
      child: Stack(
        fit: StackFit.expand,
        children: [
          // Photo
          if (photoUrl != null)
            Image.network(
              photoUrl,
              fit: BoxFit.cover,
              headers: _token != null
                  ? {'Authorization': 'Bearer $_token'}
                  : {},
              errorBuilder: (_, __, ___) => _buildPlaceholder(user.username),
              loadingBuilder: (ctx, child, progress) {
                if (progress == null) return child;
                return _buildPlaceholder(user.username);
              },
            )
          else
            _buildPlaceholder(user.username),

          // Username — top-left corner
          Positioned(
            top: 6,
            left: 6,
            child: Container(
              padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 3),
              decoration: BoxDecoration(
                color: Colors.black.withOpacity(0.55),
                borderRadius: BorderRadius.circular(6),
              ),
              child: Text(
                user.username,
                style: const TextStyle(
                  color: Colors.white,
                  fontSize: 11,
                  fontWeight: FontWeight.w600,
                  shadows: [
                    Shadow(color: Colors.black87, blurRadius: 4),
                  ],
                ),
                maxLines: 1,
                overflow: TextOverflow.ellipsis,
              ),
            ),
          ),

          // Age badge top-right
          if (user.age != null)
            Positioned(
              top: 6,
              right: 6,
              child: Container(
                padding:
                    const EdgeInsets.symmetric(horizontal: 5, vertical: 2),
                decoration: BoxDecoration(
                  color: Colors.black.withOpacity(0.65),
                  borderRadius: BorderRadius.circular(8),
                ),
                child: Text(
                  '${user.age}',
                  style: const TextStyle(
                    color: Colors.white,
                    fontSize: 11,
                    fontWeight: FontWeight.bold,
                  ),
                ),
              ),
            ),

          // Block button — bottom-left
          Positioned(
            left: 6,
            bottom: 6,
            child: GestureDetector(
              onTap: () => _blockUser(user.id),
              child: Container(
                width: 32,
                height: 32,
                decoration: BoxDecoration(
                  color: Colors.black.withOpacity(0.65),
                  shape: BoxShape.circle,
                ),
                child: const Icon(
                  Icons.close,
                  color: Colors.white,
                  size: 18,
                ),
              ),
            ),
          ),

          // Like button — bottom-right
          Positioned(
            right: 6,
            bottom: 6,
            child: GestureDetector(
              onTap: () => _likeUser(user),
              child: Container(
                width: 32,
                height: 32,
                decoration: BoxDecoration(
                  color: Colors.black.withOpacity(0.65),
                  shape: BoxShape.circle,
                ),
                child: Icon(
                  Icons.favorite,
                  color: _likedIds.contains(user.id)
                      ? Colors.red
                      : Colors.grey,
                  size: 18,
                ),
              ),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildPlaceholder(String username) {
    return Container(
      color: Colors.blueAccent.withOpacity(0.15),
      child: Center(
        child: Text(
          username.isNotEmpty ? username[0].toUpperCase() : '?',
          style: const TextStyle(
            fontSize: 32,
            fontWeight: FontWeight.bold,
            color: Colors.blueAccent,
          ),
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Discover'),
        actions: [
          IconButton(
            icon: const Icon(Icons.settings_outlined, color: Colors.white),
            onPressed: () => Navigator.of(context).push(
              MaterialPageRoute(builder: (_) => const SettingsScreen()),
            ),
          ),
        ],
      ),
      body: RefreshIndicator(
        onRefresh: _refresh,
        child: _buildBody(),
      ),
    );
  }

  Widget _buildBody() {
    if (_users.isEmpty && _isLoading) {
      return const Center(
          child: CircularProgressIndicator(color: Colors.blueAccent));
    }

    if (_users.isEmpty && _errorMessage != null) {
      return Center(
        child: Padding(
          padding: const EdgeInsets.all(24),
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              const Icon(Icons.error_outline, size: 48, color: Colors.redAccent),
              const SizedBox(height: 12),
              Text(_errorMessage!,
                  textAlign: TextAlign.center,
                  style: const TextStyle(color: Colors.redAccent)),
              const SizedBox(height: 16),
              ElevatedButton(
                  onPressed: _refresh, child: const Text('Retry')),
            ],
          ),
        ),
      );
    }

    if (_users.isEmpty) {
      return const Center(
        child: Text('No users found.',
            style: TextStyle(color: Colors.grey, fontSize: 16)),
      );
    }

    return GridView.builder(
      controller: _scrollController,
      padding: const EdgeInsets.all(8),
      itemCount: _users.length + (_hasMore ? 1 : 0),
      gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(
        crossAxisCount: 3,
        childAspectRatio: 3 / 4,
        crossAxisSpacing: 8,
        mainAxisSpacing: 8,
      ),
      itemBuilder: (context, index) {
        if (index >= _users.length) {
          // Loader tile
          return const Center(
              child: CircularProgressIndicator(color: Colors.blueAccent));
        }
        final user = _users[index];
        return GestureDetector(
          onTap: () {
            final photoUrl = (user.photoUrl
                    ?.replaceFirst('http://0.0.0.0:8000', _baseUrl)) ??
                '';
            Navigator.of(context).push(
              MaterialPageRoute(
                builder: (_) => ProfileScreen(
                  userId: user.id,
                  username: user.username,
                  age: user.age ?? 0,
                  sex: user.sex ?? 'Unknown',
                  photoUrl: photoUrl,
                ),
              ),
            );
          },
          child: _buildCard(user),
        );
      },
    );
  }
}

// ── Ranking bottom sheet ───────────────────────────────────────────────────

class _RankingSheet extends StatefulWidget {
  final List<_RankItem> items;
  final int newUserId;
  final String baseUrl;
  final String? token;
  final Future<void> Function(List<_RankItem>) onSave;

  const _RankingSheet({
    required this.items,
    required this.newUserId,
    required this.baseUrl,
    required this.token,
    required this.onSave,
  });

  @override
  State<_RankingSheet> createState() => _RankingSheetState();
}

class _RankingSheetState extends State<_RankingSheet> {
  late List<_RankItem> _items;
  bool _saving = false;
  final ScrollController _scrollController = ScrollController();

  static const _bg = Color(0xFF12121C);
  static const _surface = Color(0xFF1E1E2E);

  @override
  void initState() {
    super.initState();
    _items = List.from(widget.items);
    // Auto-scroll to the new person after the sheet renders
    WidgetsBinding.instance.addPostFrameCallback((_) {
      final newIndex = _items.indexWhere((i) => i.id == widget.newUserId);
      if (newIndex > 0 && _scrollController.hasClients) {
        final itemH = 72.0; // approximate row height
        _scrollController.animateTo(
          newIndex * itemH,
          duration: const Duration(milliseconds: 400),
          curve: Curves.easeOut,
        );
      }
    });
  }

  @override
  void dispose() {
    _scrollController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final screenH = MediaQuery.of(context).size.height;

    return Container(
      height: screenH * 0.75,
      decoration: const BoxDecoration(
        color: _bg,
        borderRadius: BorderRadius.vertical(top: Radius.circular(20)),
      ),
      child: Column(
        children: [
          // Handle
          Container(
            margin: const EdgeInsets.only(top: 10, bottom: 4),
            width: 40,
            height: 4,
            decoration: BoxDecoration(
              color: Colors.grey.shade700,
              borderRadius: BorderRadius.circular(2),
            ),
          ),
          // Title
          const Padding(
            padding: EdgeInsets.symmetric(vertical: 12),
            child: Text(
              'Rank Your Likes',
              style: TextStyle(
                color: Colors.white,
                fontSize: 18,
                fontWeight: FontWeight.bold,
              ),
            ),
          ),
          const Padding(
            padding: EdgeInsets.only(bottom: 8),
            child: Text(
              'Drag to reorder — #1 is your top pick',
              style: TextStyle(color: Colors.grey, fontSize: 13),
            ),
          ),
          const Divider(color: Color(0xFF2A2A3E), height: 1),
          // Reorderable list
          Expanded(
            child: ReorderableListView.builder(
              scrollController: _scrollController,
              padding: const EdgeInsets.symmetric(vertical: 6),
              itemCount: _items.length,
              onReorder: (oldIndex, newIndex) {
                setState(() {
                  if (newIndex > oldIndex) newIndex--;
                  final item = _items.removeAt(oldIndex);
                  _items.insert(newIndex, item);
                });
              },
              itemBuilder: (ctx, index) {
                final item = _items[index];
                final isNew = item.id == widget.newUserId;
                final photoUrl =
                    '${widget.baseUrl}/api/users/${item.id}/photo';
                return ReorderableDragStartListener(
                  key: ValueKey(item.id),
                  index: index,
                  child: Container(
                  margin: const EdgeInsets.symmetric(
                      horizontal: 12, vertical: 4),
                  decoration: BoxDecoration(
                    color: isNew
                        ? Colors.blueAccent.withOpacity(0.18)
                        : _surface,
                    borderRadius: BorderRadius.circular(12),
                    border: isNew
                        ? Border.all(
                            color: Colors.blueAccent.withOpacity(0.5),
                            width: 1.5)
                        : null,
                  ),
                  child: ListTile(
                    contentPadding: const EdgeInsets.symmetric(
                        horizontal: 12, vertical: 4),
                    leading: Row(
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        // Rank badge
                        SizedBox(
                          width: 28,
                          child: Text(
                            '#${index + 1}',
                            style: const TextStyle(
                              color: Colors.blueAccent,
                              fontWeight: FontWeight.bold,
                              fontSize: 14,
                            ),
                            textAlign: TextAlign.center,
                          ),
                        ),
                        const SizedBox(width: 8),
                        // Circular photo
                        CircleAvatar(
                          radius: 22,
                          backgroundColor:
                              Colors.blueAccent.withOpacity(0.2),
                          child: ClipOval(
                            child: Image.network(
                              photoUrl,
                              width: 44,
                              height: 44,
                              fit: BoxFit.cover,
                              headers: widget.token != null
                                  ? {
                                      'Authorization':
                                          'Bearer ${widget.token}'
                                    }
                                  : {},
                              errorBuilder: (_, __, ___) => Center(
                                child: Text(
                                  item.username.isNotEmpty
                                      ? item.username[0].toUpperCase()
                                      : '?',
                                  style: const TextStyle(
                                    fontSize: 18,
                                    fontWeight: FontWeight.bold,
                                    color: Colors.blueAccent,
                                  ),
                                ),
                              ),
                            ),
                          ),
                        ),
                      ],
                    ),
                    title: Row(
                      children: [
                        Text(
                          item.username,
                          style: const TextStyle(
                            color: Colors.white,
                            fontWeight: FontWeight.w600,
                            fontSize: 15,
                          ),
                        ),
                        if (isNew) ...[
